			Scheme:   scheme,
			Host:     r.Host,
			Path:     parsedRedirect.Path,
			RawQuery: parsedRedirect.RawQuery,
			Fragment: parsedRedirect.Fragment,
		}
		config.RedirectURL = fullRedirectURL.String()
	} else {
		// Use the provided full URL directly
		config.RedirectURL = redirectPath
	}

	// Generate the authorization URL with the state
	authURL := config.AuthCodeURL(state)

	// Set the state in a secure, HTTP-only cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
