)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// generateRandomState creates a cryptographically secure random state string
func generateRandomState() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", fmt.Errorf("failed to generate random state: %w", err)
	}
	return base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(b), nil
}

// validateRedirectURL validates that the user-provided redirect URL is trusted
func validateRedirectURL(userRedirect string, baseRedirect string) (*url.URL, error) {
	baseURL, err := url.Parse(baseRedirect)
	if err != nil {
		return nil, fmt.Errorf("invalid base redirect URL: %w", err)
	}

	userURL, err := url.Parse(userRedirect)
	if err != nil {
		return nil, fmt.Errorf("invalid user redirect URL: %w", err)
	}

	// Resolve relative URLs against the base URL
	resolvedURL := baseURL.ResolveReference(userURL)

	// Ensure the resolved URL has the same scheme and host as the base
	if resolvedURL.Scheme != baseURL.Scheme || resolvedURL.Host != baseURL.Host {
		return nil, fmt.Errorf("redirect URL must have the same scheme and host as the registered callback")
	}

	return resolvedURL, nil
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a secure random state
	state, err := generateRandomState()
	if err != nil {
		return "", err
	}

	// Validate and resolve the redirect URL
	validatedRedirectURL, err := validateRedirectURL(redirectPath, OAuthConfig.RedirectURL)
	if err != nil {
		return "", err
	}

	// Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = validatedRedirectURL.String()

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	return authURL, nil
}

