// generateRandomState creates a cryptographically secure random state string
// to prevent CSRF attacks during OAuth2 flows.
func generateRandomState() (string, error) {
	b := make([]byte, 32) // 32 bytes = 256 bits of entropy (sufficient for CSRF protection)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	// Use URL-safe base64 to avoid issues with URL parameter encoding
	return base64.URLEncoding.EncodeToString(b), nil
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth
// (supports both relative paths and absolute URLs, but only from the same origin as the configured callback).
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// 1. Generate a secure random state to prevent CSRF attacks
	state, err := generateRandomState()
	if err != nil {
		return "", err
	}

	// 2. Validate and resolve the redirect path/URL to prevent open redirects
	originalRedirect, err := url.Parse(OAuthConfig.RedirectURL)
	if err != nil {
		return "", errors.New("invalid base callback URL configuration")
	}

	userRedirectRef, err := url.Parse(redirectPath)
	if err != nil {
		return "", errors.New("invalid redirect path/URL format")
	}

	// Resolve the user's redirect against the original base URL (handles relative paths)
	resolvedRedirect := originalRedirect.ResolveReference(userRedirectRef)

	// Enforce same-origin policy to prevent open redirect attacks
	if resolvedRedirect.Scheme != originalRedirect.Scheme || resolvedRedirect.Host != originalRedirect.Host {
		return "", errors.New("redirect must target the same origin as the configured callback URL")
	}

	// 3. Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = resolvedRedirect.String()

	// 4. Generate the authorization URL with the secure state
	authURL := config.AuthCodeURL(state)

	// 5. Store the state in a secure cookie for later validation (callback handler)
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,                  // Prevent access from JavaScript (mitigates XSS)
		Secure:   true,                  // Only send over HTTPS (prevents MITM)
		SameSite: http.SameSiteLaxMode,  // Mitigate CSRF for cross-site requests
		Path:     "/",                   // Make cookie available to all paths
		MaxAge:   600,                   // Expire after 10 minutes (reduces replay risk)
	})

	return authURL, nil
}

